(169, 'en', 85, 'Facilities Booking Request', '0', '<p>هي خدمة تقدمها المؤسسة في صيانة المساكن للمواطنين بشكل مؤقت وملائم لهم و لأفراد عوائلهم لحين حصولهم علىمساكن أخرى جديدة ، و هذه الخدمة لا تغني من حصولهم على مساعدات سكنية من الجهات الحكوميةالمختصة وتخضع هذه الخدمة لشروط و معايير معينة.</p>', NULL, '0', '0', '0', '<ul>\r\n<li>أصحاب الدخل المحدود</li>\r\n<li>كبار المواطنين</li>\r\n<li>الأيتام و الأرامل و المطلقات</li>\r\n<li>أصحاب الهمم</li>\r\n<li>المجتمع</li>\r\n</ul>', '<ul>\r\n<li>الهوية الاصلية لمالك المسكن+ صورة من الهوية</li>\r\n<li>خلاصة القيد الاصلية لمالك المسكن + صوره منها</li>\r\n<li>جواز السفر لمالك المسكن + صورة منها</li>\r\n<li>شهادة راتب سارية المفعول ( لرب الأسرة + الزوجة ) / مساعدة الشئون الاجتماعية ان وجدت</li>\r\n<li>شهادة التزامات مالية من البنك سارية المفعول ان وجدت</li>\r\n<li>شهادة أملاك واراضي ورخص تجارية ( من البلدية )</li>\r\n<li>شهادة لمن يهمة الامر من برنامج زايد للاسكان</li>\r\n<li>شهادة من ملكية البيت او محضر استلام</li>\r\n<li>خارطة المسكن ( كروكي ) حديثة غير منتهية الصلاحية</li>\r\n</ul>', '<p>applicatio steps of first service</p>', '<p>0</p>', '<p>0</p>', '<p>0</p>', '0', '0'),
(170, 'ar', 85, 'طلب حجز مرافق', '0', '<p style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\"><span style=\"font-size: 14pt;\">طلب حجز مرافق (بيت الفن &ndash; مسرح دبا)</span></span></p>', '0', '0', '0', '0', '<ul>\r\n<li style=\"text-align: right;\">جهات حكومية</li>\r\n<li style=\"text-align: right;\">شركات خاصة</li>\r\n</ul>', '<ul>\r\n<li style=\"text-align: right;\">رسالة بطلب حجز مرافق</li>\r\n<li style=\"text-align: right;\">أجندة الفعالية</li>\r\n</ul>', '<h5 style=\"text-align: right;\">تسجيل الدخول أو إنشاء حساب جديد</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">في حال كان لديك حساب مسبق، أدخل اسم المستخدم وكلمة المرور ثم اضغط على \"تسجيل الدخول\"</li>\r\n<li style=\"text-align: right;\">إذا كانت هذه المرة الأولى، اختر \"تسجيل جديد\"، ثم قم بتعبئة البيانات المطلوبة واضغط على \"تسجيل\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">تأكيد التسجيل</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;ستصلك رسالة نصية (SMS) تفيد بأنه \"تم تسجيلك في منصة هيئة الفجيرة للثقافة والإعلام بنجاح.\"</li>\r\n<li style=\"text-align: right;\">كما ستتلقى رسالة بريد إلكتروني تتضمن بيانات اعتمادك للدخول إلى المنصة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;تقديم الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">بعد تسجيل الدخول، انتقل إلى قائمة الخدمات واختر \"طلب جديد\" ضمن خدمة \"طلب حجز مرافق\"</li>\r\n<li style=\"text-align: right;\">&nbsp;قم بتعبئة البيانات المطلوبة وإرفاق المستندات اللازمة&nbsp;</li>\r\n<li style=\"text-align: right;\">اضغط على \"حفظ\" لإرسال الطلب</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;استلام تأكيد التقديم</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;ستصلك رسالة (SMS) تؤكد أنه \"تم إدخال طلب حجز مرافق بنجاح\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;مراجعة الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;سيتم مراجعة طلبك</li>\r\n<li style=\"text-align: right;\">&nbsp;عند الانتهاء من مراجعة الطلب ، ستتلقى رسالة (SMS) نصها</li>\r\n<li style=\"text-align: right;\">\"تم الانتهاء من طلب حجز المرافق في هيئة الفجيرة للثقافة والإعلام... يرجى الاتصال للمتابعة\"</li>\r\n</ul>', '<h5 style=\"text-align: right;\" data-start=\"189\" data-end=\"301\">ما نوع المرفق المطلوب حجزه</h5>\r\n<p style=\"text-align: right;\" data-start=\"189\" data-end=\"301\">(قاعة فعاليات &ndash; مسرح &ndash; استوديو تصوير &ndash; قاعة اجتماعات &ndash; مساحة خارجية &ndash; أخرى)</p>\r\n<h5 style=\"text-align: right;\" data-start=\"306\" data-end=\"407\">ما الغرض من استخدام المرفق؟</h5>\r\n<p style=\"text-align: right;\" data-start=\"306\" data-end=\"407\">(فعالية ثقافية &ndash; تدريب &ndash; تصوير &ndash; اجتماع &ndash; نشاط مجتمعي &ndash; غير ذلك)</p>\r\n<h5 style=\"text-align: right;\" data-start=\"412\" data-end=\"515\">التاريخ والمدة المطلوبة للحجز</h5>\r\n<p style=\"text-align: right;\" data-start=\"412\" data-end=\"515\">(تاريخ البداية &ndash; تاريخ الانتهاء &ndash; الأوقات اليومية للاستخدام)</p>\r\n<h5 style=\"text-align: right;\" data-start=\"520\" data-end=\"645\">هل يتطلب النشاط تجهيزات خاصة أو دعمًا فنّيًا من الهيئة؟</h5>\r\n<p style=\"text-align: right;\" data-start=\"520\" data-end=\"645\">(مثل أنظمة صوت، إضاءة، أجهزة عرض، أو ترتيبات لوجستية إضافية)</p>', '<ul>\r\n<li style=\"text-align: right;\">يجب تقديم طلب الحجز قبل تاريخ الفعالية المطلوب بـ 15 يوم عمل على الأقل، ولن يُنظر في الطلبات المتأخرة</li>\r\n<li style=\"text-align: right;\">يخضع قبول الحجز لتقييم هيئة الفجيرة للثقافة والإعلام، ويحق لها رفض الطلب دون إبداء الأسباب</li>\r\n<li style=\"text-align: right;\"><strong>&nbsp;يجب أن تكون طبيعة الفعالية متوافقة مع أهداف ورسالة الهيئة، ويُمنع استخدام المرافق في<br></strong>\r\n<ul>\r\n<li style=\"text-align: right;\">الأنشطة السياسية أو الحزبية</li>\r\n<li style=\"text-align: right;\">الفعاليات التجارية البحتة دون موافقة مسبقة</li>\r\n<li style=\"text-align: right;\">الفعاليات المخالفة للقوانين أو الآداب العامة</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">يتعين على الجهة المنظمة تقديم جميع المستندات المطلوبة (رخصة، خطة الفعالية، جدول التوقيت، التصاميم الإعلانية...إلخ) خلال مدة أقصاها 7 أيام من تاريخ الطلب</li>\r\n<li style=\"text-align: right;\">يُشترط الحصول على موافقة الهيئة على كافة المواد الدعائية أو الإعلامية الخاصة بالفعالية قبل نشرها أو توزيعها</li>\r\n<li style=\"text-align: right;\">يمنع تعديل تجهيزات أو بنية المرافق دون تصريح مسبق من الهيئة، وأي ضرر يلحق بالمكان أو محتوياته تتحمله الجهة المستأجرة</li>\r\n<li style=\"text-align: right;\">تلتزم الجهة المنظمة بمراعاة الطاقة الاستيعابية للمرفق والضوابط المتعلقة بالسلامة العامة والدفاع المدني</li>\r\n<li style=\"text-align: right;\">لا تتحمل الهيئة أي مسؤولية عن الحوادث أو الأضرار الناتجة عن الإهمال أو مخالفة التعليمات من قبل الجهة المنظمة أو المشاركين</li>\r\n<li style=\"text-align: right;\">يلتزم مقدم الطلب بسداد كامل الرسوم المستحقة خلال المدة المحددة من قبل الهيئة. ويخضع إلغاء الحجز لسياسة استرداد تعتمد على وقت الإلغاء</li>\r\n<li style=\"text-align: right;\">يُمنع التنازل عن الحجز لطرف ثالث دون إذن كتابي من الهيئة</li>\r\n<li style=\"text-align: right;\">لا يجوز استخدام شعار أو اسم الهيئة أو صور المرافق في أي إعلان دون موافقة خطية مسبقة</li>\r\n<li style=\"text-align: right;\">تحتفظ الهيئة بحق الإشراف على الفعالية أثناء التنفيذ، وطلب إيقافها أو إلغائها في حال حدوث مخالفات جسيمه</li>\r\n<li style=\"text-align: right;\">تخضع جميع الحجوزات والأنشطة المرتبطة بها للقوانين والأنظمة المعمول بها في إمارة الفجيرة ودولة الإمارات العربية المتح</li>\r\n<li style=\"text-align: right;\">الموافقة على الحجز تُعد قبولًا والتزامًا بجميع ما ورد في هذه الشروط والأحكام</li>\r\n</ul>', '<p style=\"text-align: right;\">سيتم احتساب الرسوم بعد التقديم واستلام الطلب</p>', '0', '0'),
(171, 'en', 86, 'Advertisement Permission Request', '0', '<p>details service 2</p>', NULL, '0', '0', '0', '<p>dfdffdff audience service 2</p>', '<p>dfdffdff docs service two</p>', '<p>dfdffdff docs steps two</p>', '<p>0</p>', '<p>0</p>', '<p>0</p>', '0', '0');
INSERT INTO `posts_lang` (`row_id`, `lang`, `post_id`, `name`, `short`, `details`, `txt1`, `txt2`, `txt3`, `txt4`, `area1`, `area2`, `area3`, `area4`, `area5`, `area6`, `keyss`, `descc`) VALUES
(172, 'ar', 86, 'طلب حجز لافتات إعلانيه', '0', '<p>تتيح هيئة الفجيرة للثقافة والإعلام حجز واستخدام عدد من المساحات الإعلانية (لافتات إعلانية) ضمن مواقع محددة ومعتمدة في إمارة الفجيرة، وذلك للأغراض الترويجية أو الإعلامية أو الثقافية</p>\r\n<h5>أماكن&nbsp; اللوحات الإعلانية</h5>\r\n<ul>\r\n<li>بجانب فندق شاطيء الفجيرة</li>\r\n<li>مقابل السنشري مول</li>\r\n<li>مسافي الفجيرة</li>\r\n<li>&nbsp;مقابل القيادة العامة لشرطة الفجيرة القديمة</li>\r\n</ul>\r\n<h5>حجم اللوحات الإعلانية</h5>\r\n<ul>\r\n<li>قياس اللوحات الاعلانية الحالية = 8&times;4 متر مربع</li>\r\n</ul>', '0', '0', '0', '0', '<ul>\r\n<li style=\"text-align: right;\">جهات حكومية</li>\r\n<li style=\"text-align: right;\">شركات خاصة</li>\r\n</ul>', '<ul>\r\n<li style=\"text-align: right;\">رسالة بطلب حجز مساحة اعلانية</li>\r\n<li style=\"text-align: right;\">صورة ومحتوى الإعلان</li>\r\n</ul>', '<h5 style=\"text-align: right;\">تسجيل الدخول أو إنشاء حساب جديد</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;في حال كان لديك حساب مسبق، أدخل اسم المستخدم وكلمة المرور ثم اضغط على \"تسجيل الدخول\"</li>\r\n<li style=\"text-align: right;\">&nbsp;إذا كانت هذه المرة الأولى، اختر \"تسجيل جديد\"، ثم قم بتعبئة البيانات المطلوبة واضغط على \"تسجيل\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">تأكيد التسجيل</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">ستصلك رسالة نصية (SMS) تفيد بأنه \"تم تسجيلك في منصة هيئة الفجيرة للثقافة والإعلام بنجاح\"</li>\r\n<li style=\"text-align: right;\">كما ستتلقى رسالة بريد إلكتروني تتضمن بيانات اعتمادك للدخول إلى المنصة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">تقديم الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">قم بتعبئة البيانات المطلوبة وإرفاق المستندات اللازمة</li>\r\n<li style=\"text-align: right;\">اضغط على \"حفظ\" لإرسال الطلب</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp; &nbsp;استلام تأكيد التقديم</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">ستصلك رسالة (SMS) تؤكد أنه \"تم إدخال طلب حجز اللوحات الإعلانية بنجاح\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">مراجعة الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">سيتم مراجعة طلبك</li>\r\n<li style=\"text-align: right;\">عند الانتهاء من مراجعة الطلب، ستتلقى رسالة (SMS) نصها</li>\r\n<li style=\"text-align: right;\">\"تم الانتهاء من طلب حجز اللوحات الإعلانية في هيئة الفجيرة للثقافة والإعلام... يرجى الاتصال للمتابعة\"</li>\r\n</ul>', '<h5 style=\"text-align: right;\">ما نوع الإعلان أو محتواه؟</h5>\r\n<p style=\"text-align: right;\">(تجاري &ndash; ثقافي &ndash; توعوي &ndash; فعالية &ndash; تهنئة &ndash; أخرى)</p>\r\n<h5 style=\"text-align: right;\">ما مدة عرض الإعلان؟</h5>\r\n<p style=\"text-align: right;\">(تاريخ البداية &ndash; تاريخ الانتهاء &ndash; عدد الأيام المطلوبة.)</p>\r\n<h5 style=\"text-align: right;\">ما هي تفاصيل الجهة أو الفعالية التي تُمثّلها اللافتة؟</h5>\r\n<p style=\"text-align: right;\">(اسم الجهة &ndash; الغرض من الإعلان &ndash; الفئة المستهدفة)</p>\r\n<h5 style=\"text-align: right;\">هل ترغب في خدمات تصميم أو طباعة مقدّمة من الهيئة؟</h5>\r\n<p style=\"text-align: right;\">(نعم &ndash; يرجى التوضيح)</p>', '<h5 style=\"text-align: right;\">أولا :- شروط تقديم الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">يجب تقديم طلب الحجز قبل الموعد المقترح لبدء عرض الإعلان بمدة لا تقل عن سبعة (7) أيام عمل</li>\r\n<li style=\"text-align: right;\"><strong>&nbsp;يشترط تقديم المستندات التاليه</strong>\r\n<ul>\r\n<li style=\"text-align: right;\">نسخة من الرخصة التجارية سارية المفعول (للجهات والشركات)</li>\r\n<li style=\"text-align: right;\">نسخة من الهوية الإماراتية أو جواز السفر لمقدم الطلب</li>\r\n<li style=\"text-align: right;\">التصميم النهائي للإعلان (بصيغة رقمية عالية الجودة)</li>\r\n<li style=\"text-align: right;\">تعبئة نموذج طلب الحجز المعتمد من الهيئة</li>\r\n<li style=\"text-align: right;\">دفع الرسوم المقررة حسب مدة الحجز والموقع المختار</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\"><strong>لا يعتبر الحجز مؤكدًا إلا بعد</strong>\r\n<ul>\r\n<li style=\"text-align: right;\">مراجعة التصميم والموافقة عليه من الهيئة</li>\r\n<li style=\"text-align: right;\">استكمال المستندات وسداد الرسوم</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">ثانيا :- معايير وضوابط المحتوى الإعلاني</h5>\r\n<ul>\r\n<li style=\"text-align: right;\"><strong>يجب أن يلتزم المحتوى الإعلاني بالقيم الثقافية والمجتمعية لدولة الإمارات العربية المتحدة، ويُمنع أن يتضمن&nbsp;</strong></li>\r\n<li style=\"text-align: right;\">أي محتوى سياسي، ديني، طائفي، أو أخلاقي مخل</li>\r\n<li style=\"text-align: right;\">أي إساءة مباشرة أو غير مباشرة لأفراد، جهات، رموز وطنية أو دينية</li>\r\n<li style=\"text-align: right;\">&nbsp;</li>\r\n<li style=\"text-align: right;\">أي صور أو عبارات تتعارض مع الآداب العامة</li>\r\n<li style=\"text-align: right;\">تحتفظ الهيئة بالحق الكامل في رفض أي تصميم دون الحاجة لتبرير أسباب الرفض، أو طلب تعديلات جوهرية قبل منحه الموافقة النهائية</li>\r\n<li style=\"text-align: right;\">يمنع استخدام أي شعارات رسمية أو رموز وطنية دون تصريح مسبق من الجهات المختصة</li>\r\n<li style=\"text-align: right;\">يمنع تعديل الإعلان بعد تركيبه دون موافقة خطية من الهيئة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">ثالثا :- التزامات الجهة المُعلِنة</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">تلتزم الجهة المُعلِنة بالمحتوى الذي تم اعتماده من قبل الهيئة، وتتحمل المسؤولية الكاملة عن دقة وصحة المعلومات والعروض المدرجة في الإعلان</li>\r\n<li style=\"text-align: right;\">تلتزم الجهة بدفع كافة الرسوم المستحقة قبل بدء عرض الإعلان، ويُعد أي تأخير في السداد مبررًا لإلغاء الحج</li>\r\n<li style=\"text-align: right;\">في حال طلب الإلغاء بعد اعتماد التصميم وجدولة العرض، لا يحق للجهة المطالبة باسترداد المبلغ المدفوع</li>\r\n<li style=\"text-align: right;\">تتحمل الجهة كامل المسؤولية عن أي ضرر ناتج عن الإعلان أو تركيبه أو محتواه، بما في ذلك المطالبات القانونية أو الحقوق الفكرية</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">رابعا :- الجوانب الفنية والتنفيذية</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">تلتزم الهيئة بتركيب الإعلان وفقًا للمواصفات الفنية المعتمدة لكل موقع</li>\r\n<li style=\"text-align: right;\">في حال تعرّض الإعلان للتلف بسبب عوامل طبيعية أو فنية خارجة عن إرادة الهيئة، فإن مسؤولية إعادة التركيب أو التعويض تُقدّر حسب الحالة</li>\r\n<li style=\"text-align: right;\">لا يُسمح باستخدام أي مؤثرات إضافية (مثل الإضاءة، أو الصوت) إلا بتصريح منفصل</li>\r\n<li style=\"text-align: right;\">يمنع عرض أي إعلان يتجاوز المساحة المخصصة أو يخل بمنظر الموقع أو البيئة المحيطة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">خامسا :- أحكام عامة</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">تحتفظ هيئة الفجيرة للثقافة والإعلام بالحق في تعديل أو تحديث هذه الشروط والأحكام في أي وقت دون إشعار مسبق</li>\r\n<li style=\"text-align: right;\">يُعتبر تقديم الطلب والتوقيع عليه إقرارًا بالاطلاع الكامل على هذه الشروط والأحكام والموافقة عليها</li>\r\n<li style=\"text-align: right;\">تخضع جميع التعاملات والمحتويات المرتبطة بهذه الخدمة لأحكام القوانين والأنظمة المعمول بها في إمارة الفجيرة ودولة الإمارات العربية المتحدة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">في حال مخالفة أي من الشروط المذكورة، تحتفظ الهيئة بحق</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">إلغاء الإعلان فورًا</li>\r\n<li style=\"text-align: right;\">منع الجهة من الحجز مستقبلاً</li>\r\n<li style=\"text-align: right;\">اتخاذ الإجراءات القانونية اللازمة</li>\r\n</ul>', '<p style=\"text-align: right;\">سيتم احتساب الرسوم بعد التقديم واستلام الطلب</p>', '0', '0'),
(173, 'en', 87, 'Event Permission Request', '0', '<p>It is a service provided to customers to obtain security approval to begin practicing events activities in all forms.</p>\r\n<p>&nbsp;</p>', NULL, '0', '0', '0', '<p>1. Government sectors</p>\r\n<p>2. Private sectors</p>\r\n<p>3. Individuals</p>', '<p>1. A copy of the Trade/Commercial license.</p>\r\n<p>2. A copy of the Team passport or Emirates ID.</p>\r\n<p>3. A memo from the entity requesting the service.</p>\r\n<p>4. A copy of the bank receipt for the transfer to the Authority&rsquo;s account.</p>', '<ul>\r\n<li><strong><u>Contact Us:&nbsp;</u></strong></li>\r\n</ul>\r\n<p>Public Relations Department - Fujairah Culture and Media Authority:</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Tel: 092014444</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Email: <a href=\"mailto:info@fcma.gov.ae\">info@fcma.gov.ae</a></p>\r\n<p>Official working hours (7:30 am - 3:30 pm) and Friday (7:30 am - 12 pm)</p>', '<p>0</p>', '<p>0</p>', '<p>0</p>', '0', '0'),
(174, 'ar', 87, 'طلب تصريح فعاليات', '0', '<p>هي خدمة تقدم للمتعاملين للحصول على عدم ممانعة رسمية للبدء في مزاولة أنشطة الفعاليات بجميع أشكالها.</p>', '0', '0', '0', '0', '<ul>\r\n<li style=\"text-align: right;\">القطاعات الحكومية</li>\r\n<li style=\"text-align: right;\">القطاعات الخاصة</li>\r\n<li style=\"text-align: right;\"><span style=\"font-size: 12pt;\">الأفراد (أن لا تقل أعمارهم عن 18 سنة)</span></li>\r\n</ul>', '<ul>\r\n<li style=\"text-align: right;\">صورة من الرخصة التجارية.</li>\r\n<li style=\"text-align: right;\">صورة من الإيصال البنكي بالتحويل لحساب الهيئة</li>\r\n<li style=\"text-align: right;\">رسالة من الجهة المنظمة للفعالية</li>\r\n<li style=\"text-align: right;\">كشف بأسماء المحاضرين وصورة من الجوازات أو بطاقات هوية المعنيين.&nbsp;</li>\r\n</ul>', '<h5 style=\"text-align: right;\">&nbsp;تسجيل الدخول أو إنشاء حساب جديد</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp; في حال كان لديك حساب مسبق، أدخل اسم المستخدم وكلمة المرور ثم اضغط على \"تسجيل الدخول\"</li>\r\n<li style=\"text-align: right;\">&nbsp;إذا كانت هذه المرة الأولى، اختر \"تسجيل جديد\"، ثم قم بتعبئة البيانات المطلوبة واضغط على \"تسجيل\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;تأكيد التسجيل</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp; ستصلك رسالة نصية (SMS) تفيد بأنه \"تم تسجيلك في منصة هيئة الفجيرة للثقافة والإعلام بنجاح\"</li>\r\n<li style=\"text-align: right;\">كما ستتلقى رسالة بريد إلكتروني تتضمن بيانات اعتمادك للدخول إلى المنصة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;تقديم الطلب</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;بعد تسجيل الدخول، انتقل إلى قائمة الخدمات واختر \"طلب جديد\" ضمن خدمة \"طلب تصريح فعاليات\"</li>\r\n<li style=\"text-align: right;\">&nbsp; &nbsp;قم بتعبئة البيانات المطلوبة وإرفاق المستندات اللازمة</li>\r\n<li style=\"text-align: right;\">اضغط على \"حفظ\" لإرسال الطلب</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">استلام تأكيد التقديم</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp; ستصلك رسالة (SMS) تؤكد أنه \"تم إدخال طلب تصريح فعاليات بنجاح\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;مراجعة الطلب والموافقة</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;سيتم مراجعة طلبك والحصول على الموافقات اللازمة</li>\r\n<li style=\"text-align: right;\">&nbsp;في حال الموافقة، ستتلقى رسالة (SMS) نصها<br>\"تمت الموافقة على طلبك. يرجى تسجيل الدخول إلى حسابك ودفع الرسوم لإتمام العملية\"&nbsp;</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">&nbsp;دفع الرسوم</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">بعد تسجيل الدخول، انتقل إلى \"متابعة الطلبات\" من القائمة الرئيسية، واختر \"طلب تصريح فعاليات\"</li>\r\n<li style=\"text-align: right;\">اضغط على \"دفع الرسوم\" للانتقال إلى صفحة الدفع الإلكتروني</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">إتمام المعاملة وطباعة التصريح</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">بعد مراجعة تفاصيل الدفع وتأكيده من قبل المحاسب، ستصلك رسالة (SMS) تفيد بـ<br>\"تم إكمال المعاملة. يمكنك تسجيل الدخول إلى حسابك وطباعة الطلب\"</li>\r\n<li style=\"text-align: right;\">لطباعة التصريح، قم بالدخول إلى حسابك، ثم اختر \"متابعة الطلبات\"، واضغط على أيقونة \"طباعة تصريح الفعاليات\"</li>\r\n</ul>', '<h5 style=\"text-align: right;\">نوع الفعالية المراد تنظيمها</h5>\r\n<p style=\"text-align: right;\">(ثقافية &ndash; فنية &ndash; إعلامية &ndash; رياضية &ndash; تعليمية &ndash; اجتماعية &ndash; أخرى)</p>\r\n<h5 style=\"text-align: right;\">أين موقع إقامة الفعالية؟</h5>\r\n<p style=\"text-align: right;\">(يرجى تحديد المكان بالتفصيل في امارة الفجيرة، مع ذكر إن كان مغلقًا أو مفتوحًا.)</p>\r\n<h5 style=\"text-align: right;\">تاريخ ومدة الفعالية</h5>\r\n<p style=\"text-align: right;\">(تاريخ البداية &ndash; تاريخ الانتهاء &ndash; أوقات الفعالية اليومية إن وجدت.)</p>\r\n<h5 style=\"text-align: right;\">هل تتطلب الفعالية تجهيزات خاصة أو دعم من الهيئة؟</h5>\r\n<p style=\"text-align: right;\">(مثل أنظمة صوت، شاشات عرض، تغطية إعلامية، أو تصاريح إضافية.)</p>', '<ul>\r\n<li style=\"text-align: right;\">يجب أن يكون مقدم الطلب جهة مرخصة رسميًا، مثل شركات تنظيم الفعاليات أو مالكي القاعات والمرافق التي تُقام فيها الفعاليات.</li>\r\n<li style=\"text-align: right;\">يتم تقديم طلب التصريح مع كافة المستندات المطلوبة عبر القنوات الرسمية المعتمدة (البريد الإلكتروني أو الواتساب).</li>\r\n<li style=\"text-align: right;\">يجب تقديم الطلب قبل موعد الفعالية بمدة لا تقل عن 5 أيام عمل.</li>\r\n<li style=\"text-align: right;\">يُطبق رسوم مستعجل قدره 200 درهم اضافي على الطلبات المقدمة خلال أقل من 3 أيام عمل من تاريخ الفعالية.</li>\r\n<li style=\"text-align: right;\">يلزم الحصول على تصريح لكل فنان مشارك في الفعالية، ويصدر تصريح الفنان من هيئة الفجيرة للثقافة والإعلام بعد استيفاء كافة الشروط والمستندات المطلوبة.</li>\r\n<li style=\"text-align: right;\">إذا كان عمر الفنان أقل من 21 عامًا، يجب إرفاق خطاب عدم ممانعة من ولي الأمر.</li>\r\n<li style=\"text-align: right;\">في حال توزيع تذاكر مجانية لدخول الفعالية، يجب على المنظم الالتزام بالإرشادات الصادرة من الهيئة بشأن نظام التذاكر، والتي تهدف إلى تنظيم الدخول وضمان انتظام الفعالية وعدم تجاوز الطاقة الاستيعابية للمكان.</li>\r\n<li style=\"text-align: right;\">يتوجب على المنظمين الحصول على كافة التصاريح المطلوبة من الجهات الحكومية الأخرى حسب نوع الفعالية.</li>\r\n<li style=\"text-align: right;\">تعتمد الهيئة قاعدة بيانات موحدة لتنسيق الفعاليات وتفادي تضارب المواعيد والمواقع.</li>\r\n<li style=\"text-align: right;\">يُعرف الحدث بأنه أي فعالية ثقافية، إعلامية، فنية، تعليمية، ترفيهية، دينية، رياضية، صحية أو تجارية تُقام في إمارة الفجيرة.</li>\r\n<li style=\"text-align: right;\">في حال رغبة الجهة المنظمة بإلغاء الفعالية، يجب إشعار الهيئة خطيًا قبل 5 أيام عمل على الأقل.</li>\r\n<li style=\"text-align: right;\">تُسترد رسوم التصريح فقط إذا تم الإلغاء ضمن المهلة المحددة.</li>\r\n<li style=\"text-align: right;\">يجب تقديم طلبات تعديل التصريح خطيًا قبل 3 أيام عمل على الأقل من موعد الفعالية.</li>\r\n<li style=\"text-align: right;\">تقديم الطلب يعني الموافقة الكاملة على جميع الشروط والأحكام والالتزام بها.</li>\r\n<li style=\"text-align: right;\">لأي استفسارات، يرجى التواصل مع هيئة الفجيرة للثقافة والإعلام عبر القنوات الرسمية.</li>\r\n</ul>', '<p style=\"text-align: right;\">500 درهم عن كل يوم فعالية +200 درهم خدمات أخرى + ضريبة القيمة المضافة</p>', '0', '0'),
(175, 'en', 88, 'Filming Permission Request', '0', '<p>It is a service through which the concerned party (companies - individuals) is provided with a no-objection certificate for filming (television - film - commercial) after completing the required documentations.</p>\r\n<p>&nbsp;</p>', NULL, '0', '0', '0', '<p>1. Government sectors</p>\r\n<p>2. Private sectors</p>\r\n<p>3. Individuals</p>', '<p>&nbsp; &nbsp;1. A copy of the Trade/Commercial license.</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp;2. A copy of the Team passport or Emirates ID.</p>\r\n<p>3. A memo from the entity requesting the service.</p>\r\n<p>4. A copy of the bank receipt for the transfer to the Authority&rsquo;s account.</p>', '<p>Public Relations Department - Fujairah Culture and Media Authority:</p>\r\n<p>Tel: 092014444</p>\r\n<p>Email:&nbsp;<a href=\"mailto:info@fcma.gov.ae\">info@fcma.gov.ae</a></p>\r\n<p>Official working hours (7:30 am - 3:30 pm) and Friday (7:30 am - 12 pm)</p>', '<div>\r\n<p><strong>Lorem Ipsum</strong>&nbsp;is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.</p>\r\n</div>\r\n<div>faq</div>', '<p>policy en</p>', '<p>fees en</p>', '0', '0'),
(176, 'ar', 88, 'طلب تصريح تصوير', '0', '<p>​هي خدمة يتم من خلالها تزويد صاحب العلاقة (شركات &ndash; افراد) شهادة عدم ممانعة من التصوير (تلفزيوني &ndash; سنيمائي - اعلاني) بعد استيفاء الأوراق المطلوبة.</p>', '0', '0', '0', '0', '<ul>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">القطاعات الحكومية</span></li>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">القطاعات الخاصة</span></li>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">الأفراد (أن لا تقل أعمارهم عن 18 سنة)</span></li>\r\n</ul>', '<ul>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">صورة من الرخصة التجارية.</span></li>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">صورة من جوازات أو بطاقات فريق التصوير.</span></li>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">رسالة من الجهة الطالبة للخدمة.</span></li>\r\n<li style=\"direction: rtl; text-align: right;\"><span style=\"font-size: 12pt;\">صورة من الإيصال البنكي بالتحويل لحساب الهيئة</span></li>\r\n</ul>', '<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">&nbsp; تسجيل الدخول أو إنشاء حساب جديد</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">\"في حال كان لديك حساب مسبق، أدخل اسم المستخدم وكلمة المرور ثم اضغط على \"تسجيل الدخول</li>\r\n<li style=\"text-align: right;\">\"إذا كانت هذه المرة الأولى، اختر \"تسجيل جديد\"، ثم قم بتعبئة البيانات المطلوبة واضغط على \"تسجيل</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">تأكيد التسجيل</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;\"ستصلك رسالة نصية (SMS) تفيد بأنه \"تم تسجيلك في منصة هيئة الفجيرة للثقافة والإعلام بنجاح</li>\r\n<li style=\"text-align: right;\">كما ستتلقى رسالة بريد إلكتروني تتضمن بيانات اعتمادك للدخول إلى المنصة</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">تقديم الطلب</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;\"بعد تسجيل الدخول، انتقل إلى قائمة الخدمات واختر \"طلب جديد\" ضمن خدمة \"طلب تصريح تصوير</li>\r\n<li style=\"text-align: right;\">قم بتعبئة البيانات المطلوبة وإرفاق المستندات اللازمة</li>\r\n<li style=\"text-align: right;\">اضغط على \"حفظ\" لإرسال الطلب</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\">استلام تأكيد التقديم&nbsp;</h5>\r\n<ul>\r\n<li style=\"text-align: right;\">ستصلك رسالة (SMS) تؤكد أنه \" تم إدخال طلب تصريح تصوير بنجاح\"</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">&nbsp;مراجعة الطلب والموافقة</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">&nbsp;سيتم مراجعة طلبك والحصول على الموافقات اللازمة</li>\r\n<li style=\"text-align: right;\">في حال الموافقة ستتلقى رساله (SMS)&nbsp; نصها</li>\r\n<li style=\"text-align: right;\">تمت الموافقة على طلبك يرجى تسجيل الدخول إلى حسابك ودفع الرسوم لإتمام العملية</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">&nbsp; دفع الرسوم</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">بعد تسجيل الدخول، انتقل إلى \"متابعة الطلبات\" من القائمة الرئيسية واختر \"طلب تصريح تصوير\"</li>\r\n<li style=\"text-align: right;\">&nbsp;اضغط على \"دفع الرسوم\" للانتقال إلى صفحة الدفع الإلكتروني</li>\r\n</ul>\r\n<h5 style=\"text-align: right;\"><span style=\"color: rgb(0, 0, 0);\">&nbsp;إتمام المعاملة وطباعة التصريح</span></h5>\r\n<ul>\r\n<li style=\"text-align: right;\">بعد مراجعة تفاصيل الدفع وتأكيده من قبل المحاسب، ستصلك رسالة (SMS) تفيد بـ</li>\r\n<li style=\"text-align: right;\">&nbsp; \"تم إكمال المعاملة. يمكنك تسجيل الدخول إلى حسابك وطباعة الطلب\"</li>\r\n<li style=\"text-align: right;\">لطباعة التصريح، قم بالدخول إلى حسابك، ثم اختر \"متابعة الطلبات\"، واضغط على أيقونة \"طباعة تصريح التصوير</li>\r\n</ul>', '<h5 style=\"text-align: right;\">ما الغرض من التصوير؟</h5>\r\n<p style=\"text-align: right;\">(أمثلة: إنتاج إعلامي، أعلان، مشروع طلابي، محتوى ترويجي...)</p>\r\n<h5 style=\"text-align: right;\">ما هي المواقع أو الأماكن المراد التصوير فيها؟</h5>\r\n<p style=\"text-align: right;\">(يرجى تحديد المواقع بدقة داخل إمارة الفجيرة.)</p>\r\n<h5 style=\"text-align: right;\">تاريخ ومدة التصوير</h5>\r\n<p style=\"text-align: right;\">(تاريخ البداية &ndash; تاريخ الانتهاء &ndash; عدد الأيام - الساعات المطلوبة.)</p>\r\n<h5 style=\"text-align: right;\">هل يتضمن التصوير استخدام معدات خاصة أو طائرات بدون طيار (درون)؟</h5>\r\n<p style=\"text-align: right;\">(نعم، مع تحديد نوع المعدات إن وجدت.)</p>', '<ul>\r\n<li style=\"text-align: right;\">يجب تقديم طلب التصريح قبل موعد التصوير بخمسة (5) أيام عمل على الأقل ويستغرق الاجراء يوم عمل واحد، مع استكمال كافة المتطلبات والمستندات</li>\r\n<li style=\"text-align: right;\">يجب إرفاق رسالة رسمية من الجهة الطالبة للتصوير توضح\r\n<ul>\r\n<li style=\"text-align: right;\">غاية التصوير</li>\r\n<li style=\"text-align: right;\">المواقع المطلوبة</li>\r\n<li style=\"text-align: right;\">تاريخ ومدة التصوير</li>\r\n<li style=\"text-align: right;\">أسماء وأعداد فريق العمل</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">تفاصيل خطة العمل<br>\r\n<ul>\r\n<li style=\"text-align: right;\">يُشترط تقديم التراخيص التجارية والقانونية السارية للجهة الطالبة</li>\r\n<li style=\"text-align: right;\">تعبئة استمارة معلومات كاملة عن جميع أفراد طاقم العمل، مرفقة بوثائق الهوية والتأشيرات والإقامات والبطاقات المهنية، حسب ما هو مطلوب</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">تعبئة وتوقيع تعهدين رسميين\r\n<ul>\r\n<li style=\"text-align: right;\">الالتزام بأخلاقيات العمل الإعلامي وعدم مخالفة قوانين وأنظمة دولة الإمارات العربية المتحدة</li>\r\n<li style=\"text-align: right;\">الالتزام باستخدام المواد المصورة للأغراض المذكورة فقط في الطلب الرسمي وعدم توظيفها لأي غرض آخر دون إذن مسبق.</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">تخضع بعض المواقع في الإمارة لتصاريح إضافية من جهات أمنية أو تنظيمية، خاصة\r\n<ul>\r\n<li style=\"text-align: right;\">المطارات</li>\r\n<li style=\"text-align: right;\">المواقع الحكومية الحساسة</li>\r\n<li style=\"text-align: right;\">المناطق الأثرية والتراثية</li>\r\n<li style=\"text-align: right;\">المنشآت غير التابعة للهيئة</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">يحظر التصوير في المواقع التالية إلا بموافقة خطية مسبقة من الجهات المختصة\r\n<ul>\r\n<li style=\"text-align: right;\">نقاط التفتيش الأمنية</li>\r\n<li style=\"text-align: right;\">مرافق الجمارك والهجرة</li>\r\n<li style=\"text-align: right;\">المرافق العسكرية أو الشرطية</li>\r\n<li style=\"text-align: right;\">مناطق تشغيل المعدات الحساسة</li>\r\n</ul>\r\n</li>\r\n<li style=\"text-align: right;\">لا يُسمح بحمل أو استخدام معدات أو أدوات خطرة أو محظورة خلال عملية التصوير، ويجب التصريح بكافة المعدات المستخدمة مع ذكر النوع والرقم التسلسلي</li>\r\n<li style=\"text-align: right;\">يجب الحصول على تصريح خاص لاستخدام الطائرات بدون طيار (درون) من الجهات المختصة، ويُمنع تشغيلها في أي موقع دون موافقة رسمية</li>\r\n<li style=\"text-align: right;\">الهيئة غير مسؤولة عن أي انتهاك للأنظمة القانونية أو التعاقدية من قبل الجهة الطالبة أو أفراد طاقمها، وتحتفظ بحق إلغاء التصريح أو اتخاذ الإجراءات القانونية في حال حدوث أي مخالفة</li>\r\n<li style=\"text-align: right;\">جميع المواد المصورة تخضع لحق المراجعة من قبل الهيئة، ويجوز للهيئة طلب نسخة منها للاطلاع، أو للاستخدام التوثيقي غير التجاري</li>\r\n<li style=\"text-align: right;\">لا يجوز استخدام شعار الهيئة أو اسمها أو أي مرفق تابع لها ضمن المادة المصورة دون إذن مسبق</li>\r\n<li style=\"text-align: right;\">التصريح صالح فقط للفترة والمواقع المحددة في الموافقة الرسمية، وأي تعديل يتطلب إعادة التقديم بطلب جديد</li>\r\n<li style=\"text-align: right;\">يحق للهيئة رفض أي طلب دون إبداء الأسباب، كما يحق لها تعليق أو سحب التصريح في أي وقت ترى فيه إخلالًا بالشروط</li>\r\n<li style=\"text-align: right;\">يخضع تقديم التصاريح وإجراءاتها للقوانين والأنظمة المعمول بها في إمارة الفجيرة ودولة الإمارات العربية المتحدة<br><br></li>\r\n</ul>', '<p style=\"text-align: right; padding-left: 40px;\">&nbsp; 500 درهم عن كل يوم تصوير + 200 درهم رسوم خدمات أخرى + ضريبة القيمة المضافة</p>', '0', '0'),
