(881, 'en', 4, 'Our Strategy', '0', '<div>\r\n<p><strong>Lorem Ipsum</strong>&nbsp;is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.<br><br></p>\r\n</div>\r\n<div>&nbsp;</div>', '0', '0', '0', '0', '0', '0', '0', '0', NULL, NULL, '0', '0'),
(882, 'ar', 4, 'التسويق العقاري', '0', '<p><strong>الرؤية</strong></p>\r\n<p>\"الفجيرة وجهة عالمية للثقافة، رائدة إعلاميًّا، وحاضنة للإبداع.\"&nbsp;</p>\r\n<p><strong>الرسالة&nbsp;</strong><br>\"تعزيز هوية الفجيرة الثقافية والإعلامية والارتقاء بها بشكل إبداعي مبتكر وتنمية الموهوبين والمبدعين.\"</p>\r\n<p><strong>الأهداف الإستراتيجية</strong></p>\r\n<ul>\r\n<li>تعزيز هوية الفجيرة الثقافية والإعلامية عالميا عبر الشراكات والتعاون الاستراتيجي</li>\r\n<li>تعزيز التكامل بين القطاعين الثقافي والإعلامي من خلال برامج ومبادرات استراتيجية مشتركة&nbsp;</li>\r\n<li>قيادة منظومة الحوكمة الثقافية مع الشركاء ضمن نهج إستراتيجي وتعاون فعال(أساسي)</li>\r\n<li>تفعيل التراث الثقافي للفجيرة كمورد للتعليم والابتكار والانفتاح العالمي</li>\r\n<li>&nbsp;تقديم خدمات استثنائية تعزز من ترسيخ ثقافة التميز والابتكار وتمكين الكفاءات البشرية</li>\r\n<li>&nbsp;تنمية قطاعي الثقافة والإعلام والفنون كمحركات للتنمية الاقتصادية المستدامة ونمو الصناعات الإبداعية.</li>\r\n</ul>\r\n<p><strong>&nbsp;القيم</strong></p>\r\n<ul>\r\n<li style=\"text-align: right;\">الأصالة&nbsp;</li>\r\n<li style=\"text-align: right;\">الوفاء للتراث&nbsp;</li>\r\n<li style=\"text-align: right;\">&nbsp;المسؤولية</li>\r\n<li style=\"text-align: right;\">الدقة</li>\r\n<li style=\"text-align: right;\">المصداقية</li>\r\n<li style=\"text-align: right;\">الموضوعية</li>\r\n</ul>', '0', '0', '0', '0', '0', '0', '0', '0', NULL, NULL, '0', '0'),
